parameters.jsCode:
try {
  const agentOutput = $input.first().json.output || $input.first().json.text || '';
  let sms = agentOutput.replace(/^["']|["']$/g, '').trim();

  let phone = String($('Process One at a Time1').first().json.phone || '').replace(/[^0-9]/g, '');

  if (phone && !phone.startsWith('+')) {
    phone = '+' + (phone.startsWith('1') ? phone : '1' + phone);
  }

  return [{
    json: {
      sms_message: sms,
      mobile_phone: phone,
      from_number: '+1XXXXXXXXXX',
      chars: sms.length,
      request_body: {
        from: '+1XXXXXXXXXX',
        to: [phone],
        content: sms
      }
    }
  }];
} catch (e) {
  return [{
    json: {
      error: e.message,
      input_keys: Object.keys($input.first().json)
    }
  }];
}

